import{_ as o,o as e,c as a,ag as s}from"./chunks/framework.DmiIFzQJ.js";const n="/docs/keyboard-layout-iso-jis-tkl.png",A=JSON.parse('{"title":"Custom Fonts & CSS","description":"","frontmatter":{},"headers":[],"relativePath":"custom-fonts.md","filePath":"custom-fonts.md"}'),i={name:"custom-fonts.md"};function l(r,t,d,h,p,g){return e(),a("div",null,[...t[0]||(t[0]=[s('<h1 id="custom-fonts-css" tabindex="-1">Custom Fonts &amp; CSS <a class="header-anchor" href="#custom-fonts-css" aria-label="Permalink to &quot;Custom Fonts &amp; CSS&quot;">​</a></h1><h2 id="css-import" tabindex="-1">CSS Metadata <a class="header-anchor" href="#css-import" aria-label="Permalink to &quot;CSS Metadata {#css-import}&quot;">​</a></h2><p>The original <a href="https://www.keyboard-layout-editor.com/" target="_blank" rel="noreferrer">Keyboard Layout Editor</a> provided <a href="https://github.com/ijprest/keyboard-layout-editor/wiki/Custom-Styles" target="_blank" rel="noreferrer">fine-grained</a> control over keyboard CSS style via a <code>css</code> metadata field defined in a layout. This allows using any web font (like Google Fonts) for key label rendering.</p><p>When you import a KLE layout that contains CSS metadata, kle-ng displays that value in the <strong>CSS</strong> field of the <strong>Keyboard Metadata</strong> panel.</p><h2 id="supported-syntax" tabindex="-1">Supported CSS Features <a class="header-anchor" href="#supported-syntax" aria-label="Permalink to &quot;Supported CSS Features {#supported-syntax}&quot;">​</a></h2><p>kle-ng supports only a minimal subset of CSS for loading fonts:</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@import</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> url</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">https://fonts.googleapis.com/css2?family=Noto+Sans+JP</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>The font name is automatically extracted from the URL and applied globally to all canvas text.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>It is not possible to define different fonts for different key labels — the font applies to all labels on all keys.</p><p>All other CSS expressions are ignored and have no effect.</p></div><h2 id="adding-a-custom-font" tabindex="-1">Adding a Custom Font <a class="header-anchor" href="#adding-a-custom-font" aria-label="Permalink to &quot;Adding a Custom Font&quot;">​</a></h2><h3 id="adding-a-font-from-google-fonts" tabindex="-1">Adding a Font from Google Fonts <a class="header-anchor" href="#adding-a-font-from-google-fonts" aria-label="Permalink to &quot;Adding a Font from Google Fonts&quot;">​</a></h3><ol><li>Open the <strong>Keyboard Metadata</strong> panel</li><li>In the <strong>CSS</strong> field, add an <code>@import</code> statement with your Google Fonts URL</li><li>The font name is automatically extracted and applied to canvas rendering</li></ol><h3 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h3><p><strong>Adding Noto Sans JP:</strong></p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@import</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> url</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">https://fonts.googleapis.com/css2?family=Noto+Sans+JP</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>This is especially useful for layouts with international characters, special symbols, or stylistic typography. Following layout has been rendered with Noto Sans JP on a system without Japanese fonts installed.</p><p><img src="'+n+'" alt="Keyboard with Japanese font" class="docs-screenshot"></p><p><a href="https://editor.keyboard-tools.xyz/#--gwpAAssugBBDCkAA8lzOBCgC2DCkAB8lycBCgDRDCkCiXICQ2AIEMKQADWXAABhCgCxDAmDVqZwGmte1nXdbxhFYZMrGAE2ktWNvCjVUc1PiabgpApEwclDBjQSAGrkDSTBO5kkD1lPwIJYCAISOgCQmoA28YJgU5EBN2Pgw0EPMJp8pECwTrGANUMgD9DDLgBTDJcgC3DLGgB7DGCQ1bb+gAyDC+Qz7A19MWUz3nYHTHxBIAJaSWwcQTE6TQw5vxvhWz4gADpCkgA9pCkgBtpPJ9xAA" target="_blank" rel="noreferrer">Open in editor →</a></p><h2 id="finding-google-fonts-urls" tabindex="-1">Finding Google Fonts URLs <a class="header-anchor" href="#finding-google-fonts-urls" aria-label="Permalink to &quot;Finding Google Fonts URLs&quot;">​</a></h2><ol><li>Go to <a href="https://fonts.google.com/" target="_blank" rel="noreferrer">fonts.google.com</a> and select a font.</li><li>Click <strong>Get font</strong>, then <strong>Get embed code</strong>.</li><li>Copy the URL from the <code>@import</code> line shown (e.g., <code>https://fonts.googleapis.com/css2?family=Roboto+Mono</code>).</li><li>Paste it into the CSS field as shown in the example above.</li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><p>The font loads from Google&#39;s servers when the layout is opened. If the browser cannot reach Google Fonts (e.g., in certain regions or behind a firewall), the fallback system font is used instead.</p></div><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="font-not-appearing" tabindex="-1">Font Not Appearing <a class="header-anchor" href="#font-not-appearing" aria-label="Permalink to &quot;Font Not Appearing&quot;">​</a></h3><p><strong>Font doesn&#39;t appear after adding the CSS</strong> — The font is applied when the CSS field loses focus (on blur). Click outside the CSS text area to trigger the load. A notification appears when the font is applied successfully.</p><h3 id="system-font-still-showing" tabindex="-1">System Font Still Showing <a class="header-anchor" href="#system-font-still-showing" aria-label="Permalink to &quot;System Font Still Showing&quot;">​</a></h3><p><strong>Labels still show the system font</strong> — Check that the <code>@import</code> URL is correct and that the family name in the URL matches exactly. If you typed the font name manually, ensure capitalization and spacing match the Google Fonts URL format (e.g., <code>Noto+Sans+JP</code> not <code>Noto Sans JP</code>).</p><h3 id="mixed-fonts" tabindex="-1">Mixed Fonts <a class="header-anchor" href="#mixed-fonts" aria-label="Permalink to &quot;Mixed Fonts&quot;">​</a></h3><p><strong>Different fonts for different keys are not possible</strong> — kle-ng applies one font globally. If you need mixed scripts (e.g., Latin and Japanese on the same layout), choose a font that supports both character ranges, such as Noto Sans.</p><h2 id="css-metadata-in-kle-export" tabindex="-1">CSS Metadata in KLE Export <a class="header-anchor" href="#css-metadata-in-kle-export" aria-label="Permalink to &quot;CSS Metadata in KLE Export&quot;">​</a></h2><p>The CSS field value is preserved when exporting to KLE JSON format. This means layouts with custom fonts remain compatible with other KLE-based tools.</p>',30)])])}const f=o(i,[["render",l]]);export{A as __pageData,f as default};
